import * as echarts from 'echarts';
import request from '@/utils/request';
export default {
  name: "Home",
  data() {
    return {
      config: {
        systemName: "无人机管理系统V1.0",
        inspectFreq: 30,
        logRetention: 90,
        maxHeight: 120,
        maxBattery: 45,
        alertThreshold: 5
      },
      detailDialogVisible: false,
      currentWeek: "",
      // 改为“周”维度
      // 周维度任务详情模拟数据（12月1-4周）
      weekDetailData: {
        "12月第1周": [8, 10, 12],
        "12月第2周": [10, 12, 15],
        "12月第3周": [9, 11, 13],
        "12月第4周": [12, 14, 16]
      }
    };
  },
  methods: {
    async initCharts() {
      // 12月各周数据（贴合无人机业务）
      const taskData = [30, 37, 33, 42]; // 12月1-4周执行任务数
      const errorData = [3, 2, 4, 1]; // 12月1-4周异常次数
      const weeks = ['12月第1周', '12月第2周', '12月第3周', '12月第4周']; // X轴改为周维度

      // 1. 柱状图（12月各周执行任务数）
      const barChart = echarts.init(document.getElementById('bar'));
      const barOption = {
        title: {
          text: '12月各周无人机执行任务数',
          textStyle: {
            fontSize: 16
          }
        },
        tooltip: {
          trigger: 'axis',
          formatter: params => {
            const item = params[0];
            return `
              <div style="padding: 5px;">
                <div>${item.name}</div>
                <div style="color: ${item.color};">执行任务数：${item.value} 次</div>
                <div>环比增长：${Math.round(Math.random() * 10)}%</div>
              </div>
            `;
          }
        },
        legend: {
          data: ['执行任务数'],
          right: 20
        },
        xAxis: {
          type: 'category',
          data: weeks,
          // 替换为周维度
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          axisLabel: {
            rotate: 0
          } // 适配周维度文字显示
        },
        yAxis: {
          type: 'value',
          name: '任务数（次）',
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          splitLine: {
            lineStyle: {
              type: 'dashed',
              color: '#eee'
            }
          }
        },
        series: [{
          name: '执行任务数',
          data: taskData,
          type: 'bar',
          itemStyle: {
            color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{
              offset: 0,
              color: '#4299E1'
            }, {
              offset: 1,
              color: '#2B6CB0'
            }])
          },
          emphasis: {
            itemStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{
                offset: 0,
                color: '#66B1FF'
              }, {
                offset: 1,
                color: '#337ECC'
              }]),
              shadowBlur: 10,
              shadowColor: 'rgba(0,0,0,0.3)'
            }
          }
        }]
      };
      barChart.setOption(barOption);

      // 点击柱状图（周维度下钻）
      barChart.on('click', params => {
        this.currentWeek = params.name;
        this.detailDialogVisible = true;
        this.initDetailChart();
      });

      // 2. 折线图（12月各周异常次数）
      const lineChart = echarts.init(document.getElementById('line'));
      const lineOption = {
        title: {
          text: '12月各周无人机异常次数',
          textStyle: {
            fontSize: 16
          }
        },
        tooltip: {
          trigger: 'axis',
          axisPointer: {
            type: 'shadow'
          }
        },
        legend: {
          data: ['异常次数', '预警阈值'],
          right: 20
        },
        xAxis: {
          type: 'category',
          data: weeks,
          // 替换为周维度
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          }
        },
        yAxis: {
          type: 'value',
          name: '次数（次）',
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          splitLine: {
            lineStyle: {
              type: 'dashed',
              color: '#eee'
            }
          },
          markLine: {
            data: [{
              name: '预警阈值',
              yAxis: this.config.alertThreshold,
              lineStyle: {
                type: 'dashed',
                color: '#F56C6C'
              }
            }]
          }
        },
        series: [{
          name: '异常次数',
          data: errorData,
          type: 'line',
          smooth: true,
          lineStyle: {
            width: 3,
            color: '#4299E1'
          },
          itemStyle: {
            color: '#2B6CB0',
            borderWidth: 2,
            borderColor: '#fff'
          },
          areaStyle: {
            color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{
              offset: 0,
              color: 'rgba(66, 153, 225, 0.5)'
            }, {
              offset: 1,
              color: 'rgba(66, 153, 225, 0.1)'
            }])
          },
          emphasis: {
            lineStyle: {
              width: 4
            },
            itemStyle: {
              color: '#66B1FF',
              shadowBlur: 10
            }
          }
        }, {
          name: '预警阈值',
          type: 'line',
          data: [this.config.alertThreshold, this.config.alertThreshold, this.config.alertThreshold, this.config.alertThreshold],
          lineStyle: {
            type: 'dashed',
            color: '#F56C6C'
          },
          symbol: 'none'
        }]
      };
      lineChart.setOption(lineOption);

      // 窗口自适应
      window.addEventListener('resize', () => {
        barChart.resize();
        lineChart.resize();
        if (this.detailDialogVisible) this.initDetailChart();
      });
    },
    // 周维度详情图表（饼图）
    initDetailChart() {
      const detailChart = echarts.init(document.getElementById('detailChart'));
      const detailOption = {
        title: {
          text: `${this.currentWeek} 任务类型分布`,
          textStyle: {
            fontSize: 16
          }
        },
        tooltip: {
          trigger: 'item',
          formatter: '{b}: {c} 次 ({d}%)'
        },
        legend: {
          orient: 'vertical',
          left: 10,
          data: ['巡逻任务', '巡检任务', '应急任务']
        },
        series: [{
          type: 'pie',
          radius: ['40%', '70%'],
          center: ['50%', '50%'],
          data: [{
            name: '巡逻任务',
            value: this.weekDetailData[this.currentWeek][0]
          }, {
            name: '巡检任务',
            value: this.weekDetailData[this.currentWeek][1]
          }, {
            name: '应急任务',
            value: this.weekDetailData[this.currentWeek][2]
          }],
          itemStyle: {
            color: params => {
              const colors = ['#4299E1', '#67C21A', '#F56C6C'];
              return colors[params.dataIndex];
            },
            emphasis: {
              shadowBlur: 10,
              shadowColor: 'rgba(0,0,0,0.3)'
            }
          },
          label: {
            show: false
          },
          labelLine: {
            show: false
          }
        }]
      };
      detailChart.setOption(detailOption);
    }
  },
  mounted() {
    this.initCharts();
  }
};
